if (! function_exists('geo_haversine')) {
    function geo_haversine($lat1, $lon1, $lat2, $lon2, $unit = null)
    {
        // Validate input ranges
        $lat1 = (float)$lat1;
        $lon1 = (float)$lon1;
        $lat2 = (float)$lat2;
        $lon2 = (float)$lon2;

        if ($lat1 < -90 || $lat1 > 90) {
            return json_encode(['error' => "lat1 ($lat1) out of range [-90, 90]"]);
        }
        if ($lat2 < -90 || $lat2 > 90) {
            return json_encode(['error' => "lat2 ($lat2) out of range [-90, 90]"]);
        }
        if ($lon1 < -180 || $lon1 > 180) {
            return json_encode(['error' => "lon1 ($lon1) out of range [-180, 180]"]);
        }
        if ($lon2 < -180 || $lon2 > 180) {
            return json_encode(['error' => "lon2 ($lon2) out of range [-180, 180]"]);
        }

        $lat1r = deg2rad($lat1);
        $lon1r = deg2rad($lon1);
        $lat2r = deg2rad($lat2);
        $lon2r = deg2rad($lon2);
        $unit = isset($unit) ? $unit : 'km';

        $dlat = $lat2r - $lat1r;
        $dlon = $lon2r - $lon1r;

        $a = sin($dlat / 2) * sin($dlat / 2) +
             cos($lat1r) * cos($lat2r) *
             sin($dlon / 2) * sin($dlon / 2);
        $c = 2 * atan2(sqrt($a), sqrt(1 - $a));

        $earthRadiusKm = 6371.0;
        $distanceKm = $earthRadiusKm * $c;

        $distance = $distanceKm;
        $unitLabel = 'kilometers';

        if ($unit === 'miles') {
            $distance = $distanceKm * 0.621371;
            $unitLabel = 'miles';
        } elseif ($unit === 'nautical') {
            $distance = $distanceKm * 0.539957;
            $unitLabel = 'nautical miles';
        }

        // Compass bearing (initial bearing)
        $y = sin($dlon) * cos($lat2r);
        $x = cos($lat1r) * sin($lat2r) - sin($lat1r) * cos($lat2r) * cos($dlon);
        $bearing = rad2deg(atan2($y, $x));
        $bearing = fmod($bearing + 360, 360);

        // Cardinal direction
        $cardinals = ['N', 'NNE', 'NE', 'ENE', 'E', 'ESE', 'SE', 'SSE', 'S', 'SSW', 'SW', 'WSW', 'W', 'WNW', 'NW', 'NNW'];
        $bearingIndex = round($bearing / 22.5) % 16;
        $cardinal = $cardinals[$bearingIndex];

        // Midpoint
        $midLat = rad2deg(atan2(
            sin($lat1r) + sin($lat2r),
            sqrt((cos($lat1r) + cos($lat2r) * cos($dlon)) ** 2 + (cos($lat2r) * sin($dlon)) ** 2)
        ));
        $midLon = rad2deg($lon1r + $dlon / 2);

        return json_encode([
            'point1' => ['lat' => round($lat1, 4), 'lon' => round($lon1, 4)],
            'point2' => ['lat' => round($lat2, 4), 'lon' => round($lon2, 4)],
            'distance' => round($distance, 4),
            'unit' => $unitLabel,
            'distance_km' => round($distanceKm, 4),
            'distance_miles' => round($distanceKm * 0.621371, 4),
            'initial_bearing' => round($bearing, 2) . '° ' . $cardinal,
            'midpoint' => ['lat' => round($midLat, 4), 'lon' => round($midLon, 4)],
        ]);
    }
